6	
7	---------------------------------------------------------------------------------------------------
8	-- Description
9	---------------------------------------------------------------------------------------------------
10	-- This entity implements a full AXI master. In contrast to olo_axi_master_simple,
11	-- this entity can do unaligned transfers and it supports different width for the
12	-- AXI interface than for the data interface. The AXI interface can be wider than
13	-- the data interface but not vice versa.
14	-- The flexibility of doing unaligned transfers is paid by lower performance for
15	-- very small transfers. There is an overhead of some clock cycles per command.
16	--
17	-- Documentation:
18	-- https://github.com/open-logic/open-logic/blob/main/doc/axi/olo_axi_master_full.md
19	--
20	-- Note: The link points to the documentation of the latest release. If you
21	--       use an older version, the documentation might not match the code.
22	
23	---------------------------------------------------------------------------------------------------
24	-- Libraries
25	---------------------------------------------------------------------------------------------------
26	library ieee;
27	    use ieee.std_logic_1164.all;
28	    use ieee.numeric_std.all;
29	    use ieee.std_logic_misc.all;
30	
31	library work;
32	    use work.olo_base_pkg_math.all;
33	    use work.olo_base_pkg_logic.all;
34	    use work.olo_base_pkg_string.all;
35	
36	---------------------------------------------------------------------------------------------------
37	-- Entity
38	---------------------------------------------------------------------------------------------------
39	entity olo_axi_master_full is
40	    generic (
41	        -- AXI Configuration
42	        AxiAddrWidth_g             : natural range 12 to 64  := 32;
43	        AxiDataWidth_g             : natural range 8 to 1024 := 32;
44	        AxiMaxBeats_g              : natural range 1 to 256  := 256;
45	        AxiMaxOpenTransactions_g   : natural range 1 to 8    := 8;
46	        -- User Configuration
47	        UserTransactionSizeBits_g  : natural                 := 24;
48	        DataFifoDepth_g            : natural                 := 1024;
49	        UserDataWidth_g            : natural                 := 32;
50	        ImplRead_g                 : boolean                 := true;
51	        ImplWrite_g                : boolean                 := true;
52	        RamBehavior_g              : string                  := "RBW"
53	    );
54	    port (
55	        -- Control Signals
56	        Clk             : in    std_logic;
57	        Rst             : in    std_logic;
58	        -- User Command Interface
59	        CmdWr_Addr      : in    std_logic_vector(AxiAddrWidth_g - 1 downto 0)            := (others => '0');
60	        CmdWr_Size      : in    std_logic_vector(UserTransactionSizeBits_g - 1 downto 0) := (others => '0');
61	        CmdWr_LowLat    : in    std_logic                                                := '0';
62	        CmdWr_Valid     : in    std_logic                                                := '0';
63	        CmdWr_Ready     : out   std_logic;
64	        -- User Command Interface
65	        CmdRd_Addr      : in    std_logic_vector(AxiAddrWidth_g - 1 downto 0)            := (others => '0');
66	        CmdRd_Size      : in    std_logic_vector(UserTransactionSizeBits_g - 1 downto 0) := (others => '0');
67	        CmdRd_LowLat    : in    std_logic                                                := '0';
68	        CmdRd_Valid     : in    std_logic                                                := '0';
69	        CmdRd_Ready     : out   std_logic;
70	        -- Write Data
71	        Wr_Data         : in    std_logic_vector(UserDataWidth_g - 1 downto 0)           := (others => '0');
72	        Wr_Valid        : in    std_logic                                                := '0';
73	        Wr_Ready        : out   std_logic;
74	        -- Read Data
75	        Rd_Data         : out   std_logic_vector(UserDataWidth_g - 1 downto 0);
76	        Rd_Last         : out   std_logic;
77	        Rd_Valid        : out   std_logic;
78	        Rd_Ready        : in    std_logic                                                := '1';
79	        -- Response
80	        Wr_Done         : out   std_logic;
81	        Wr_Error        : out   std_logic;
82	        Rd_Done         : out   std_logic;
83	        Rd_Error        : out   std_logic;
84	        -- AXI Address Write Channel
85	        M_Axi_AwAddr    : out   std_logic_vector(AxiAddrWidth_g - 1 downto 0);
86	        M_Axi_AwLen     : out   std_logic_vector(7 downto 0);
87	        M_Axi_AwSize    : out   std_logic_vector(2 downto 0);
88	        M_Axi_AwBurst   : out   std_logic_vector(1 downto 0);
89	        M_Axi_AwLock    : out   std_logic;
90	        M_Axi_AwCache   : out   std_logic_vector(3 downto 0);
91	        M_Axi_AwProt    : out   std_logic_vector(2 downto 0);
92	        M_Axi_AwValid   : out   std_logic;
93	        M_Axi_AwReady   : in    std_logic                                                := '0';
94	        -- AXI Write Data Channel
95	        M_Axi_WData     : out   std_logic_vector(AxiDataWidth_g - 1 downto 0);
96	        M_Axi_WStrb     : out   std_logic_vector(AxiDataWidth_g / 8 - 1 downto 0);
97	        M_Axi_WLast     : out   std_logic;
98	        M_Axi_WValid    : out   std_logic;
99	        M_Axi_WReady    : in    std_logic                                                := '0';
100	        -- AXI Write Response Channel
101	        M_Axi_BResp     : in    std_logic_vector(1 downto 0)                             := (others => '0');
102	        M_Axi_BValid    : in    std_logic                                                := '0';
103	        M_Axi_BReady    : out   std_logic;
104	        -- AXI Read Address Channel
105	        M_Axi_ArAddr    : out   std_logic_vector(AxiAddrWidth_g - 1 downto 0);
106	        M_Axi_ArLen     : out   std_logic_vector(7 downto 0);
107	        M_Axi_ArSize    : out   std_logic_vector(2 downto 0);
108	        M_Axi_ArBurst   : out   std_logic_vector(1 downto 0);
109	        M_Axi_ArLock    : out   std_logic;
110	        M_Axi_ArCache   : out   std_logic_vector(3 downto 0);
111	        M_Axi_ArProt    : out   std_logic_vector(2 downto 0);
112	        M_Axi_ArValid   : out   std_logic;
113	        M_Axi_ArReady   : in    std_logic                                                := '0';
114	        -- AXI Read Data Channel
115	        M_Axi_RData     : in    std_logic_vector(AxiDataWidth_g - 1 downto 0)            := (others => '0');
116	        M_Axi_RResp     : in    std_logic_vector(1 downto 0)                             := (others => '0');
117	        M_Axi_RLast     : in    std_logic                                                := '0';
118	        M_Axi_RValid    : in    std_logic                                                := '0';
119	        M_Axi_RReady    : out   std_logic
120	    );
121	end entity;
122	
123	---------------------------------------------------------------------------------------------------
124	-- Architecture
125	---------------------------------------------------------------------------------------------------
126	architecture rtl of olo_axi_master_full is
127	
128	    -- *** Constants ***
129	    constant EntityName_c : string  := "olo_axi_master_full";
130	    constant AxiBytes_c   : natural := AxiDataWidth_g / 8;
131	    constant DataBytes_c  : natural := UserDataWidth_g / 8;
132	
133	    -- *** Type ***
134	    type WriteCmdFsm_t is (Idle_s, Apply_s);
135	    type WriteWconvFsm_t is (Idle_s, Transfer_s);
136	    type WriteAlignFsm_t is (Idle_s, Transfer_s, Last_s);
137	    type ReadCmdFsm_t is (Idle_s, Apply_s, WaitDataFsm_s);
138	    type ReadDataFsm_t is (Idle_s, Transfer_s, Wait_s);
139	
140	    -- *** Functions ***
141	    function alignedAddr (Addr : in unsigned(AxiAddrWidth_g-1 downto 0))
142	    return unsigned is
143	        variable Addr_v : unsigned(Addr'range) := (others => '0');
144	    begin
145	        Addr_v(Addr'left downto log2(AxiBytes_c)) := Addr(Addr'left downto log2(AxiBytes_c));
146	        return Addr_v;
147	    end function;
148	
149	    -- *** Two Process Record ***
150	    type TwoProcess_r is record
151	        -- *** Write Related Registers ***
152	        WrCmdFsm        : WriteCmdFsm_t;
153	        WrLastAddr      : unsigned(AxiAddrWidth_g - 1 downto 0);
154	        CmdWr_Ready     : std_logic;
155	        AxiWrCmd_Addr   : std_logic_vector(AxiAddrWidth_g - 1 downto 0);
156	        AxiWrCmd_Size   : std_logic_vector(UserTransactionSizeBits_g - 1 downto 0);
157	        WrAlignCmdSize  : std_logic_vector(UserTransactionSizeBits_g - 1 downto 0);
158	        AxiWrCmd_LowLat : std_logic;
159	        AxiWrCmd_Vld    : std_logic;
160	        WrWconvFsm      : WriteWconvFsm_t;
161	        WrStartTf       : std_logic;
162	        WrWordsDone     : unsigned(UserTransactionSizeBits_g - 1 downto 0);
163	        WrDataWordsCmd  : unsigned(UserTransactionSizeBits_g - 1 downto 0);
164	        WrDataWordsWc   : unsigned(UserTransactionSizeBits_g - 1 downto 0);
165	        WrAlignFsm      : WriteAlignFsm_t;
166	        WrAlignReg      : std_logic_vector(AxiDataWidth_g * 2 - 1 downto 0);
167	        WrAlignBe       : std_logic_vector(AxiBytes_c * 2 - 1 downto 0);
168	        WrShift         : unsigned(log2(AxiBytes_c) - 1 downto 0);
169	        WrAlignShift    : unsigned(log2(AxiBytes_c) - 1 downto 0);
170	        WrAlignVld      : std_logic;
171	        AxiWordCnt      : unsigned(UserTransactionSizeBits_g - 1 downto 0);
172	        WrLastBe        : std_logic_vector(AxiBytes_c - 1 downto 0);
173	        WrAlignLastBe   : std_logic_vector(AxiBytes_c - 1 downto 0);
174	        WrAlignLast     : std_logic;
175	
176	        -- *** Read Related Registers ***
177	        RdCmdFsm        : ReadCmdFsm_t;
178	        RdLastAddr      : unsigned(AxiAddrWidth_g - 1 downto 0);
179	        RdFirstAddrOffs : unsigned(log2(AxiBytes_c) - 1 downto 0);
180	        CmdRd_Ready     : std_logic;
181	        AxiRdCmd_Addr   : std_logic_vector(AxiAddrWidth_g - 1 downto 0);
182	        AxiRdCmd_LowLat : std_logic;
183	        AxiRdCmd_Vld    : std_logic;
184	        AxiRdCmd_Size   : std_logic_vector(UserTransactionSizeBits_g - 1 downto 0);
185	        RdFirstBe       : std_logic_vector(AxiBytes_c - 1 downto 0);
186	        RdLastBe        : std_logic_vector(AxiBytes_c - 1 downto 0);
187	        RdDataFsm       : ReadDataFsm_t;
188	        RdStartTf       : std_logic;
189	        RdDataEna       : std_logic;
190	        RdDatFirstBe    : std_logic_vector(AxiBytes_c - 1 downto 0);
191	        RdDatLastBe     : std_logic_vector(AxiBytes_c - 1 downto 0);
192	        RdDataWords     : unsigned(UserTransactionSizeBits_g - 1 downto 0);
193	        RdCurrentWord   : unsigned(UserTransactionSizeBits_g - 1 downto 0);
194	        RdShift         : unsigned(log2(AxiBytes_c) - 1 downto 0);
195	        RdLowIdx        : unsigned(log2(AxiBytes_c) downto 0);
196	        RdAlignShift    : unsigned(log2(AxiBytes_c) - 1 downto 0);
197	        RdAlignLowIdx   : unsigned(log2(AxiBytes_c) downto 0);
198	        RdAlignByteVld  : std_logic_vector(AxiBytes_c * 2 - 1 downto 0);
199	        RdAlignReg      : std_logic_vector(AxiDataWidth_g * 2 - 1 downto 0);
200	        RdAlignLast     : std_logic;
201	    end record;
202	
203	    signal r, r_next : TwoProcess_r;
204	
205	    -- *** Instantiation Signals ***
206	    signal WrPl_Data     : std_logic_vector(Wr_Data'range);
207	    signal WrPl_Vld      : std_logic;
208	    signal AxiWrCmd_Rdy  : std_logic;
209	    signal AxiWrDat_Rdy  : std_logic;
210	    signal AxiWrDat_Data : std_logic_vector(AxiDataWidth_g - 1 downto 0);
211	    signal WrPl_Rdy      : std_logic;
212	    signal AxiWrDat_Be   : std_logic_vector(AxiBytes_c - 1 downto 0);
213	    signal WrWconvEna    : std_logic;
214	    signal WrWconv_Vld   : std_logic;
215	    signal WrWconv_Rdy   : std_logic;
216	    signal WrWconv_Last  : std_logic;
217	    signal WrData_Vld    : std_logic;
218	    signal WrData_Data   : std_logic_vector(AxiDataWidth_g - 1 downto 0);
219	    signal WrData_Last   : std_logic;
220	    signal WrData_We     : std_logic_vector(AxiBytes_c / DataBytes_c - 1 downto 0);
221	    signal WrData_Rdy    : std_logic;
222	    signal WrDataEna     : std_logic;
223	    signal AxiRdCmd_Rdy  : std_logic;
224	    signal AxiRdDat_Rdy  : std_logic;
225	    signal AxiRdDat_Vld  : std_logic;
226	    signal AxiRdDat_Data : std_logic_vector(AxiDataWidth_g - 1 downto 0);
227	    signal AxiRdDat_Last : std_logic;
228	    signal RdPl_Rdy      : std_logic;
229	    signal RdPl_Data     : std_logic_vector(UserDataWidth_g - 1 downto 0);
230	    signal RdPl_Vld      : std_logic;
231	    signal RdPl_Last     : std_logic;
232	
233	begin
234	
235	    -- *** Assertions ***
236	    assert isPower2(AxiDataWidth_g/8)
237	        report errorMessage(EntityName_c, "AxiDataWidth_g must be a power of two of bytes")
238	        severity failure;
239	    assert UserDataWidth_g mod 8 = 0
240	        report errorMessage(EntityName_c, "UserDataWidth_g must be a multiple of 8")
241	        severity failure;
242	    assert AxiDataWidth_g mod UserDataWidth_g = 0
243	        report errorMessage(EntityName_c, "AxiDataWidth_g must be a multiple of UserDataWidth_g")
244	        severity failure;
245	    assert UserTransactionSizeBits_g <= AxiAddrWidth_g
246	        report errorMessage(EntityName_c, "UserTransactionSizeBits_g must be smaller or equal to AxiAddrWidth_g")
247	        severity failure;
248	
249	    -- *** Combinatorial Process ***
250	    p_comb : process (all) is
251	        variable v              : TwoProcess_r;
252	        variable WriteBe_v      : std_logic_vector(AxiBytes_c - 1 downto 0);
253	        variable RdAlignReady_v : std_logic;
254	        variable RdLowIdxInt_v  : integer range 0 to AxiBytes_c;
255	        variable RdDatBe_v      : std_logic_vector(AxiBytes_c - 1 downto 0);
256	    begin
257	        -- *** Keep two process variables stable ***
258	        v := r;
259	
260	        -- *** Write Related Code ***
261	        if ImplWrite_g then
262	
263	            -- *** Command FSM ***
264	            v.WrStartTf    := '0';
265	            v.AxiWrCmd_Vld := '0';
266	
267	            case r.WrCmdFsm is
268	
269	                when Idle_s =>
270	                    v.CmdWr_Ready := '1';
271	                    v.WrLastAddr  := unsigned(CmdWr_Addr) + unsigned(CmdWr_Size) - 1;
272	                    if unsigned(CmdWr_Size(log2(DataBytes_c) - 1 downto 0)) = 0 then
273	                        v.WrDataWordsCmd := resize(unsigned(CmdWr_Size(CmdWr_Size'high downto log2(DataBytes_c))), UserTransactionSizeBits_g);
274	                    else
275	                        v.WrDataWordsCmd := resize(unsigned(CmdWr_Size(CmdWr_Size'high downto log2(DataBytes_c))) + 1, UserTransactionSizeBits_g);
276	                    end if;
277	                    v.AxiWrCmd_Addr   := std_logic_vector(alignedAddr(unsigned(CmdWr_Addr)));
278	                    v.WrShift         := unsigned(CmdWr_Addr(v.WrShift'range));
279	                    v.AxiWrCmd_LowLat := CmdWr_LowLat;
280	                    if CmdWr_Valid = '1' then
281	                        v.CmdWr_Ready := '0';
282	                        v.WrCmdFsm    := Apply_s;
283	                    end if;
284	
285	                when Apply_s =>
286	                    if (AxiWrCmd_Rdy = '1') and (r.WrWconvFsm = Idle_s) and (r.WrAlignFsm = Idle_s) then
287	                        v.AxiWrCmd_Vld  := '1';
288	                        v.WrStartTf     := '1';
289	                        v.WrCmdFsm      := Idle_s;
290	                        v.CmdWr_Ready   := '1';
291	                        v.AxiWrCmd_Size := std_logic_vector(resize(shift_right(alignedAddr(r.WrLastAddr) - unsigned(r.AxiWrCmd_Addr), log2(AxiBytes_c)) + 1,
292	                                                                   UserTransactionSizeBits_g));
293	
294	                        -- Calculate byte enables for last word
295	                        for byte in 0 to AxiBytes_c - 1 loop
296	                            if r.WrLastAddr(log2(AxiBytes_c) - 1 downto 0) >= byte then
297	                                v.WrLastBe(byte) := '1';
298	                            else
299	                                v.WrLastBe(byte) := '0';
300	                            end if;
301	                        end loop;
302	
303	                    end if;
304	
305	                -- coverage off
306	                when others => null;    -- unreachable code
307	                -- coverage on
308	
309	            end case;
310	
311	            -- *** With Conversion FSM ***
312	            WrWconvEna   <= '0';
313	            WrWconv_Last <= '0';
314	
315	            case r.WrWconvFsm is
316	                -- Latch values that change for the next command that may be interpreted while the current one is running
317	                when Idle_s =>
318	                    v.WrWordsDone   := to_unsigned(1, v.WrWordsDone'length);
319	                    v.WrDataWordsWc := r.WrDataWordsCmd;
320	                    if r.WrStartTf = '1' then
321	                        v.WrWconvFsm := Transfer_s;
322	                    end if;
323	
324	                -- Execute transfer
325	                when Transfer_s =>
326	                    WrWconvEna <= '1';
327	                    if r.WrWordsDone = r.WrDataWordsWc then
328	                        WrWconv_Last <= '1';
329	                    end if;
330	                    if (WrWconv_Rdy = '1') and (WrPl_Vld = '1') then
331	                        v.WrWordsDone := r.WrWordsDone + 1;
332	                        if r.WrWordsDone = r.WrDataWordsWc then
333	                            v.WrWconvFsm := Idle_s;
334	                        end if;
335	                    end if;
336	
337	                -- coverage off
338	                when others => null; -- unreachable code
339	                -- coverage on
340	            end case;
341	
342	            -- *** Alignment FSM ***
343	            -- Initial values
344	            WrDataEna <= '0';
345	
346	            -- Word- to Byte-Enable conversion
347	            for i in 0 to AxiBytes_c - 1 loop
348	                WriteBe_v(i) := WrData_We(i / UserDataWidth_g);
349	            end loop;
350	
351	            -- FSM
352	            case r.WrAlignFsm is
353	                -- Latch values that change for the next command that may be interpreted while the current one is running
354	                when Idle_s =>
355	                    v.WrAlignReg     := (others => '0');
356	                    v.WrAlignBe      := (others => '0');
357	                    v.AxiWordCnt     := to_unsigned(1, v.AxiWordCnt'length);
358	                    v.WrAlignLast    := '0';
359	                    v.WrAlignShift   := r.WrShift;
360	                    v.WrAlignCmdSize := r.AxiWrCmd_Size;
361	                    v.WrAlignLastBe  := r.WrLastBe;
362	                    v.WrAlignVld     := '0';
363	                    if r.WrStartTf = '1' then
364	                        v.WrAlignFsm := Transfer_s;
365	                    end if;
366	
367	                -- Move data from the FIFO to AXI
368	                when Transfer_s =>
369	                    WrDataEna <= '1';
370	                    if (AxiWrDat_Rdy = '1') and ((WrData_Vld = '1') or (r.WrAlignLast = '1')) then
371	                        -- Don't add new byte enables on last data flushing
372	                        if r.WrAlignLast = '1' then
373	                            WriteBe_v := (others => '0');
374	                        end if;
375	                        -- Shift
376	                        v.WrAlignReg(AxiDataWidth_g - 1 downto 0) := r.WrAlignReg(r.WrAlignReg'left downto AxiDataWidth_g);
377	                        v.WrAlignBe(AxiBytes_c - 1 downto 0)      := r.WrAlignBe(r.WrAlignBe'left downto AxiBytes_c);
378	                        -- New Data
379	                        v.WrAlignReg((to_integer(r.WrAlignShift) + AxiBytes_c) * 8 - 1 downto to_integer(r.WrAlignShift) * 8) := WrData_Data;
380	                        v.WrAlignBe(to_integer(r.WrAlignShift) + AxiBytes_c - 1 downto to_integer(r.WrAlignShift))            := WriteBe_v;
381	                        -- Flow control
382	                        v.WrAlignVld := '1';
383	                        if r.AxiWordCnt = unsigned(r.WrAlignCmdSize) then
384	                            v.WrAlignFsm                         := Last_s;
385	                            v.WrAlignBe(AxiBytes_c - 1 downto 0) := v.WrAlignBe(AxiBytes_c - 1 downto 0) and r.WrAlignLastBe;
386	                        end if;
387	                        v.AxiWordCnt := r.AxiWordCnt + 1;
388	                        -- Force last data out
389	                        v.WrAlignLast := WrData_Last;
390	                    elsif AxiWrDat_Rdy = '1' then
391	                        v.WrAlignVld := '0';
392	                    end if;
393	
394	                -- Wait for the last beat te be accepted without reading more data from the FIFO
395	                when Last_s =>
396	                    v.WrAlignVld := '1';
397	                    if AxiWrDat_Rdy = '1' then
398	                        v.WrAlignVld := '0';
399	                        v.WrAlignFsm := Idle_s;
400	                    end if;
401	
402	                -- coverage off
403	                when others => null; -- unreachable code
404	                -- coverage on
405	            end case;
406	
407	        end if;
408	
409	        -- *** Read Related Code ***
410	        if ImplRead_g then
411	
412	            -- *** Variables ***
413	            RdLowIdxInt_v  := to_integer(r.RdAlignLowIdx);
414	            RdAlignReady_v := r.RdDataEna;
415	
416	            -- Vivado workaround
417	            for i in 0 to AxiBytes_c loop
418	                if i = RdLowIdxInt_v then
419	                    -- no new data fits into shifter, even if output is ready. This only happens for user width < axi width
420	                    if (DataBytes_c < AxiBytes_c) and (unsigned(r.RdAlignByteVld(r.RdAlignByteVld'high downto i + DataBytes_c)) /= 0) then
421	                        RdAlignReady_v := '0';
422	                    -- if output is ready, new data can be accepted (back-to-back)
423	                    elsif unsigned(r.RdAlignByteVld(r.RdAlignByteVld'high downto i)) /= 0 and RdPl_Rdy = '0' then
424	                        RdAlignReady_v := '0';
425	                    end if;
426	                end if;
427	            end loop;
428	
429	            -- *** Command FSM ***
430	            v.RdStartTf    := '0';
431	            v.AxiRdCmd_Vld := '0';
432	
433	            case r.RdCmdFsm is
434	                -- Move data from the FIFO to AXI
435	                when Idle_s =>
436	                    v.CmdRd_Ready     := '1';
437	                    v.RdLastAddr      := unsigned(CmdRd_Addr) + unsigned(CmdRd_Size) - 1;
438	                    v.RdFirstAddrOffs := unsigned(CmdRd_Addr(v.RdFirstAddrOffs'range));
439	                    v.AxiRdCmd_Addr   := std_logic_vector(alignedAddr(unsigned(CmdRd_Addr)));
440	                    v.AxiRdCmd_LowLat := CmdRd_LowLat;
441	                    v.RdShift         := unsigned(CmdRd_Addr(v.RdShift'range));
442	                    v.RdLowIdx        := to_unsigned(AxiBytes_c, v.RdLowIdx'length) - unsigned(CmdRd_Addr(v.RdShift'range));
443	                    if CmdRd_Valid = '1' then
444	                        v.CmdRd_Ready := '0';
445	                        v.RdCmdFsm    := Apply_s;
446	                    end if;
447	
448	                -- Send AXI command when core is ready
449	                when Apply_s =>
450	                    if AxiRdCmd_Rdy = '1' then
451	                        v.AxiRdCmd_Vld  := '1';
452	                        v.RdCmdFsm      := WaitDataFsm_s;
453	                        v.RdStartTf     := '1';
454	                        v.AxiRdCmd_Size := std_logic_vector(resize(shift_right(alignedAddr(r.RdLastAddr) - unsigned(r.AxiRdCmd_Addr), log2(AxiBytes_c)) + 1,
455	                                                                   UserTransactionSizeBits_g));
456	
457	                        -- Calculate byte enables for last byte
458	                        for byte in 0 to AxiBytes_c - 1 loop
459	                            if r.RdLastAddr(log2(AxiBytes_c) - 1 downto 0) >= byte then
460	                                v.RdLastBe(byte) := '1';
461	                            else
462	                                v.RdLastBe(byte) := '0';
463	                            end if;
464	                        end loop;
465	
466	                        -- Calculate byte enables for first byte
467	                        for byte in 0 to AxiBytes_c - 1 loop
468	                            if r.RdFirstAddrOffs <= byte then
469	                                v.RdFirstBe(byte) := '1';
470	                            else
471	                                v.RdFirstBe(byte) := '0';
472	                            end if;
473	                        end loop;
474	
475	                    end if;
476	
477	                -- Start data FSM before sending next command to avoid owerwriting data before it was latched
478	                when WaitDataFsm_s =>
479	                    v.RdStartTf := '1';
480	                    if r.RdDataFsm = Idle_s then
481	                        v.RdCmdFsm    := Idle_s;
482	                        v.CmdRd_Ready := '1';
483	                        v.RdStartTf   := '0';
484	                    end if;
485	
486	                -- coverage off
487	                when others => null;    -- unreachable code
488	                -- coverage on
489	            end case;
490	
491	            -- *** Data FSM ***
492	            v.RdDataEna := '0';
493	            RdDatBe_v   := (others => '1');
494	
495	            case r.RdDataFsm is
496	                when Idle_s =>
497	                    v.RdDatFirstBe  := r.RdFirstBe;
498	                    v.RdDatLastBe   := r.RdLastBe;
499	                    v.RdDataWords   := unsigned(r.AxiRdCmd_Size);
500	                    v.RdCurrentWord := to_unsigned(1, v.RdCurrentWord'length);
501	                    v.RdAlignShift  := r.RdShift;
502	                    v.RdAlignLowIdx := r.RdLowIdx;
503	                    if r.RdStartTf = '1' then
504	                        v.RdDataFsm := Transfer_s;
505	                        v.RdDataEna := '1';
506	                    end if;
507	
508	                when Transfer_s =>
509	                    v.RdDataEna := '1';
510	                    if r.RdCurrentWord = 1 then
511	                        RdDatBe_v := RdDatBe_v and r.RdDatFirstBe;
512	                    end if;
513	                    if r.RdCurrentWord = r.RdDataWords then
514	                        RdDatBe_v := RdDatBe_v and r.RdDatLastBe;
515	                    end if;
516	                    if (RdAlignReady_v = '1') and (AxiRdDat_Vld = '1') and (r.RdDataEna = '1') then
517	                        v.RdCurrentWord := r.RdCurrentWord + 1;
518	                        if r.RdCurrentWord = r.RdDataWords then
519	                            v.RdDataEna := '0';
520	                            v.RdDataFsm := Wait_s;
521	                        end if;
522	                    end if;
523	
524	                -- Wait until reception of all data is done
525	                when Wait_s =>
526	                    if unsigned(r.RdAlignByteVld) = 0 then
527	                        v.RdDataFsm := Idle_s;
528	                    end if;
529	
530	                -- coverage off
531	                when others => null; -- unreachable code
532	                -- coverage on
533	            end case;
534	
535	            -- *** Data Alignment ***
536	            AxiRdDat_Rdy <= RdAlignReady_v;
537	            RdPl_Vld     <= '0';
538	            -- shift
539	            if (RdPl_Rdy = '1') and (RdAlignReady_v = '0' or AxiRdDat_Vld = '1' or r.RdAlignLast = '1') then
540	                -- Shift is only done if data can be consumed (RdPl_Rdy) and either no new data is required for the next shift (RdAlignReady_v = '0'),
541	                -- .. the data is available (AxiRdDat_Vld = '1') or we are at the end of a transfer (r.RdAlignLast = '1')
542	                v.RdAlignReg     := zerosVector(UserDataWidth_g) & r.RdAlignReg(r.RdAlignReg'left downto UserDataWidth_g);
543	                v.RdAlignByteVld := zerosVector(DataBytes_c) & r.RdAlignByteVld(r.RdAlignByteVld'left downto DataBytes_c);
544	                if r.RdAlignLast = '1' then
545	                    RdPl_Vld <= or_reduce(r.RdAlignByteVld(DataBytes_c - 1 downto 0));
546	                else
547	                    RdPl_Vld <= and_reduce(r.RdAlignByteVld(DataBytes_c - 1 downto 0));
548	                end if;
549	            end if;
550	            -- get new data
551	            if RdAlignReady_v = '1' and AxiRdDat_Vld = '1' then
552	                v.RdAlignReg(RdLowIdxInt_v * 8 + AxiDataWidth_g - 1 downto RdLowIdxInt_v * 8) := AxiRdDat_Data;
553	                v.RdAlignByteVld(RdLowIdxInt_v + AxiBytes_c - 1 downto RdLowIdxInt_v)         := RdDatBe_v;
554	                v.RdAlignLast                                                                 := AxiRdDat_Last;
555	            end if;
556	
557	            -- Send data to FIFO (assert Last when no more data is available after this beat)
558	            RdPl_Last <= r.RdAlignLast and not (or_reduce(r.RdAlignByteVld(r.RdAlignByteVld'high downto DataBytes_c)));
559	            RdPl_Data <= r.RdAlignReg(UserDataWidth_g - 1 downto 0);
560	
561	        end if;
562	
563	        -- *** Update Signal ***
564	        r_next <= v;
565	    end process;
566	
567	    -- *** Registered Process ***
568	    p_reg : process (Clk) is
569	    begin
570	        if rising_edge(Clk) then
571	            r <= r_next;
572	            if Rst = '1' then
573	                -- *** Write Related Registers ***
574	                if ImplWrite_g then
575	                    r.WrCmdFsm     <= Idle_s;
576	                    r.CmdWr_Ready  <= '0';
577	                    r.AxiWrCmd_Vld <= '0';
578	                    r.WrWconvFsm   <= Idle_s;
579	                    r.WrStartTf    <= '0';
580	                    r.WrAlignFsm   <= Idle_s;
581	                    r.WrAlignVld   <= '0';
582	                end if;
583	                -- *** Read Related Registers ***
584	                if ImplRead_g then
585	                    r.RdCmdFsm       <= Idle_s;
586	                    r.CmdRd_Ready    <= '0';
587	                    r.AxiRdCmd_Vld   <= '0';
588	                    r.RdDataFsm      <= Idle_s;
589	                    r.RdStartTf      <= '0';
590	                    r.RdDataEna      <= '0';
591	                    r.RdAlignByteVld <= (others => '0');
592	                end if;
593	            end if;
594	        end if;
595	    end process;
596	
597	    -- *** Outputs ***
598	    CmdWr_Ready <= r.CmdWr_Ready;
599	    CmdRd_Ready <= r.CmdRd_Ready;
600	
601	    -----------------------------------------------------------------------------------------------
602	    -- Instantiations
603	    -----------------------------------------------------------------------------------------------
604	    -- AXI Master Interface
605	    AxiWrDat_Data <= r.WrAlignReg(AxiWrDat_Data'range);
606	    AxiWrDat_Be   <= r.WrAlignBe(AxiWrDat_Be'range);
607	
608	    i_axi : entity work.olo_axi_master_simple
609	        generic map (
610	            AxiAddrWidth_g              => AxiAddrWidth_g,
611	            AxiDataWidth_g              => AxiDataWidth_g,
612	            AxiMaxBeats_g               => AxiMaxBeats_g,
613	            AxiMaxOpenTransactions_g    => AxiMaxOpenTransactions_g,
614	            UserTransactionSizeBits_g   => UserTransactionSizeBits_g,
615	            DataFifoDepth_g             => DataFifoDepth_g,
616	            ImplRead_g                  => ImplRead_g,
617	            ImplWrite_g                 => ImplWrite_g,
618	            RamBehavior_g               => RamBehavior_g
619	        )
620	        port map (
621	            -- Control Signals
622	            Clk             => Clk,
623	            Rst             => Rst,
624	            -- User Command Interface
625	            CmdWr_Addr      => r.AxiWrCmd_Addr,
626	            CmdWr_Size      => r.AxiWrCmd_Size,
627	            CmdWr_LowLat    => r.AxiWrCmd_LowLat,
628	            CmdWr_Valid     => r.AxiWrCmd_Vld,
629	            CmdWr_Ready     => AxiWrCmd_Rdy,
630	            -- User Command Interface
631	            CmdRd_Addr      => r.AxiRdCmd_Addr,
632	            CmdRd_Size      => r.AxiRdCmd_Size,
633	            CmdRd_LowLat    => r.AxiRdCmd_LowLat,
634	            CmdRd_Valid     => r.AxiRdCmd_Vld,
635	            CmdRd_Ready     => AxiRdCmd_Rdy,
636	            -- Write Data
637	            Wr_Data         => AxiWrDat_Data,
638	            Wr_Be           => AxiWrDat_Be,
639	            Wr_Valid        => r.WrAlignVld,
640	            Wr_Ready        => AxiWrDat_Rdy,
641	            -- Read Data
642	            Rd_Data         => AxiRdDat_Data,
643	            Rd_Valid        => AxiRdDat_Vld,
644	            Rd_Ready        => AxiRdDat_Rdy,
645	            Rd_Last         => AxiRdDat_Last,
646	            -- Response
647	            Wr_Done         => Wr_Done,
648	            Wr_Error        => Wr_Error,
649	            Rd_Done         => Rd_Done,
650	            Rd_Error        => Rd_Error,
651	            -- AXI Address Write Channel
652	            M_Axi_AwAddr    => M_Axi_AwAddr,
653	            M_Axi_AwLen     => M_Axi_AwLen,
654	            M_Axi_AwSize    => M_Axi_AwSize,
655	            M_Axi_AwBurst   => M_Axi_AwBurst,
656	            M_Axi_AwLock    => M_Axi_AwLock,
657	            M_Axi_AwCache   => M_Axi_AwCache,
658	            M_Axi_AwProt    => M_Axi_AwProt,
659	            M_Axi_AwValid   => M_Axi_AwValid,
660	            M_Axi_AwReady   => M_Axi_AwReady,
661	            -- AXI Write Data Channel
662	            M_Axi_WData     => M_Axi_WData,
663	            M_Axi_WStrb     => M_Axi_WStrb,
664	            M_Axi_WLast     => M_Axi_WLast,
665	            M_Axi_WValid    => M_Axi_WValid,
666	            M_Axi_WReady    => M_Axi_WReady,
667	            -- AXI Write Response Channel
668	            M_Axi_BResp     => M_Axi_BResp,
669	            M_Axi_BValid    => M_Axi_BValid,
670	            M_Axi_BReady    => M_Axi_BReady,
671	            -- AXI Read Address Channel
672	            M_Axi_ArAddr    => M_Axi_ArAddr,
673	            M_Axi_ArLen     => M_Axi_ArLen,
674	            M_Axi_ArSize    => M_Axi_ArSize,
675	            M_Axi_ArBurst   => M_Axi_ArBurst,
676	            M_Axi_ArLock    => M_Axi_ArLock,
677	            M_Axi_ArCache   => M_Axi_ArCache,
678	            M_Axi_ArProt    => M_Axi_ArProt,
679	            M_Axi_ArValid   => M_Axi_ArValid,
680	            M_Axi_ArReady   => M_Axi_ArReady,
681	            -- AXI Read Data Channel
682	            M_Axi_RData     => M_Axi_RData,
683	            M_Axi_RResp     => M_Axi_RResp,
684	            M_Axi_RLast     => M_Axi_RLast,
685	            M_Axi_RValid    => M_Axi_RValid,
686	            M_Axi_RReady    => M_Axi_RReady
687	        );
688	
689	    -- *** Write Releated Code ***
690	    g_write : if ImplWrite_g generate
691	
692	        -- Write Data pipeline stage (for improved timing)
693	        WrPl_Rdy <= WrWconv_Rdy and WrWconvEna;
694	
695	        i_pl_wr_data : entity work.olo_base_pl_stage
696	            generic map (
697	                Width_g        => UserDataWidth_g
698	            )
699	            port map (
700	                Clk         => Clk,
701	                Rst         => Rst,
702	                In_Data     => Wr_Data,
703	                In_Valid    => Wr_Valid,
704	                In_Ready    => Wr_Ready,
705	                Out_Data    => WrPl_Data,
706	                Out_Valid   => WrPl_Vld,
707	                Out_Ready   => WrPl_Rdy
708	            );
709	
710	        -- Write Data With Conversion
711	        WrWconv_Vld <= WrWconvEna and WrPl_Vld;
712	        WrData_Rdy  <= AxiWrDat_Rdy and WrDataEna;
713	
714	        i_wc_wr : entity work.olo_base_wconv_n2xn
715	            generic map (
716	                InWidth_g   => UserDataWidth_g,
717	                OutWidth_g  => AxiDataWidth_g
718	            )
719	            port map (
720	                Clk         => Clk,
721	                Rst         => Rst,
722	                In_Valid    => WrWconv_Vld,
723	                In_Ready    => WrWconv_Rdy,
724	                In_Data     => WrPl_Data,
725	                In_Last     => WrWconv_Last,
726	                Out_Valid   => WrData_Vld,
727	                Out_Ready   => WrData_Rdy,
728	                Out_Data    => WrData_Data,
729	                Out_Last    => WrData_Last,
730	                Out_WordEna => WrData_We
731	            );
732	
733	    end generate;
734	
735	    g_nwrite : if not ImplWrite_g generate
736	        Wr_Ready <= '0';
737	    end generate;
738	
739	    -- *** Read Releated Code ***
740	    g_read : if ImplRead_g generate
741	        signal InData, OutData : std_logic_vector(UserDataWidth_g downto 0);
742	    begin
743	        -- Input assembly
744	        InData <= RdPl_Last & RdPl_Data;
745	
746	        -- Instance
747	        i_pl_rd_data : entity work.olo_base_pl_stage
748	            generic map (
749	                Width_g     => UserDataWidth_g+1
750	            )
751	            port map (
752	                Clk         => Clk,
753	                Rst         => Rst,
754	                In_Data     => InData,
755	                In_Valid    => RdPl_Vld,
756	                In_Ready    => RdPl_Rdy,
757	                Out_Data    => OutData,
758	                Out_Valid   => Rd_Valid,
759	                Out_Ready   => Rd_Ready
760	            );
761	
762	        -- Output disassembly
763	        Rd_Last <= OutData(UserDataWidth_g);
764	        Rd_Data <= OutData(UserDataWidth_g-1 downto 0);
765	
766	    end generate;
767	
768	    g_nread : if not ImplRead_g generate
769	        Rd_Valid <= '0';
770	        Rd_Data  <= (others => '0');
771	        Rd_Last  <= '0';
772	    end generate;
773	
774	end architecture;
775

